1090→/**
1091→ * Destructor for Value objects — frees malloc'd backing storage.
1092→ * Called automatically by the region system when a Value is destroyed.
1093→ */
1094→fn void destroy_value(void* ptr) {
1095→    Value* v = (Value*)ptr;
1096→    switch (v.tag) {
1097→        case STRING:
1098→        case ERROR:
1099→            if (v.str_val != null) {
1100→                if (v.str_val.chars != null) mem::free(v.str_val.chars);
1101→                mem::free(v.str_val);
1102→                v.str_val = null;
1103→            }
1104→        case ARRAY:
1105→            if (v.array_val != null) {
1106→                if (v.array_val.items != null) mem::free(v.array_val.items);
1107→                mem::free(v.array_val);
1108→                v.array_val = null;
1109→            }
1110→        case INSTANCE:
1111→            if (v.instance_val != null) {
1112→                mem::free(v.instance_val);
1113→                v.instance_val = null;
1114→            }
1115→        case METHOD_TABLE:
1116→            if (v.method_table_val != null) {
1117→                if (v.method_table_val.entries != null) {
1118→                    mem::free(v.method_table_val.entries);
1119→                }
1120→                mem::free(v.method_table_val);
1121→                v.method_table_val = null;
1122→            }
1123→        case CLOSURE:
1124→            if (v.closure_val != null) {
1125→                if (v.closure_val.type_sig != null) {
1126→                    mem::free(v.closure_val.type_sig);
1127→                }
1128→                mem::free(v.closure_val);
1129→                v.closure_val = null;
1130→            }
1131→        case PRIMITIVE:
1132→            if (v.prim_val != null) {
1133→                mem::free(v.prim_val);
1134→                v.prim_val = null;
1135→            }
1136→        case FFI_HANDLE:
1137→            if (v.ffi_val != null) {
1138→                if (v.ffi_val.lib_handle != null) {
1139→                    dlclose(v.ffi_val.lib_handle);
1140→                    v.ffi_val.lib_handle = null;
1141→                }
1142→                mem::free(v.ffi_val);
1143→                v.ffi_val = null;
1144→            }
1145→        case ITERATOR: {}  // iterator_val is a Value* (CLOSURE), owned by region
1146→        default: {}
1147→    }
1148→}
1149→
1150→/**
1151→ * Destructor for HashMap objects — frees malloc'd entries buffer.
1152→ * Called automatically by the region system when a HashMap is destroyed.
1153→ */
1154→fn void destroy_hashmap(void* ptr) {
1155→    HashMap* map = (HashMap*)ptr;
1156→    if (map.entries != null) {
1157→        mem::free(map.entries);
1158→        map.entries = null;
1159→    }
1160→}
1161→
1162→/**
1163→ * Destructor for Env objects — frees malloc'd bindings array.
1164→ */
1165→fn void destroy_env(void* ptr) {
1166→    Env* env = (Env*)ptr;
1167→    if (env.bindings != null) {
1168→        mem::free(env.bindings);
1169→        env.bindings = null;
1170→    }
1171→    if (env.hash_table != null) {
1172→        mem::free(env.hash_table);
1173→        env.hash_table = null;
1174→    }
1175→}
