1177→/**
1178→ * Register destructors for types with malloc'd backing storage.
1179→ * Initializes the global destructor registry if not already initialized.
1180→ */
1181→fn void register_destructors() {
1182→    if (main::g_destructor_registry.capacity == 0) {
1183→        main::g_destructor_registry.init();
1184→    }
1185→    main::g_destructor_registry.register(Value.typeid, &destroy_value);
1186→    main::g_destructor_registry.register(HashMap.typeid, &destroy_hashmap);
1187→    main::g_destructor_registry.register(Env.typeid, &destroy_env);
1188→}
