1190→/**
1191→ * Copy a Value and everything it transitively references to a target region.
1192→ * Used to promote return values out of a child frame before releasing it.
1193→ */
1194→<* @require interp != null : "copy_to_parent: null interp" *>
1195→fn Value* copy_to_parent(Value* v, Interp* interp, main::RegionHandle target) {
1196→    if (v == null) return null;
1197→    // Debug: uncomment to trace value promotion
1198→    // $if DEBUG_BUILD:
1199→    //     if (target.region_id == interp.root_region.region_id && v.tag != ValueTag.NIL && v.tag != ValueTag.INT) {
1200→    //         io::eprintfn("[debug] copy_to_parent: promoting tag=%d to root region", v.tag.ordinal);
1201→    //     }
1202→    // $endif
1203→    main::RegionHandle saved = interp.current_frame;
1204→    interp.current_frame = target;
1205→
1206→    Value* result;
1207→    switch (v.tag) {
1208→        case NIL:
1209→            result = make_nil(interp);
1210→        case INT:
1211→            result = make_int(interp, v.int_val);
1212→        case DOUBLE:
1213→            result = make_double(interp, v.double_val);
1214→        case STRING:
1215→            result = make_string(interp, v.str_val.chars[:v.str_val.len]);
1216→        case SYMBOL:
1217→            result = make_symbol(interp, v.sym_val);
1218→        case CONS: {
1219→            // Need to restore frame for recursive calls
1220→            interp.current_frame = saved;
1221→            Value* new_car = copy_to_parent(v.cons_val.car, interp, target);
1222→            Value* new_cdr = copy_to_parent(v.cons_val.cdr, interp, target);
1223→            interp.current_frame = target;
1224→            result = make_cons(interp, new_car, new_cdr);
1225→        }
1226→        case CLOSURE: {
1227→            // Shared Closure: new Value wrapper in target scope, bump refcount
1228→            result = interp.alloc_value();
1229→            result.tag = CLOSURE;
1230→            result.closure_val = v.closure_val;
1231→            result.closure_val.refcount++;
1232→            main::scope_register_dtor(interp.current_scope, (void*)result, &scope_dtor_value);
1233→        }
1234→        case PRIMITIVE:
1235→            result = v;
1236→        case PARTIAL_PRIM: {
1237→            // Deep copy: Value wrapper may be in child scope, and first_arg/second_arg may too
1238→            result = interp.alloc_value();
1239→            result.tag = PARTIAL_PRIM;
1240→            result.partial_val.func = v.partial_val.func;
1241→            result.partial_val.remaining = v.partial_val.remaining;
1242→            interp.current_frame = saved;
1243→            result.partial_val.first_arg = copy_to_parent(v.partial_val.first_arg, interp, target);
1244→            result.partial_val.second_arg = copy_to_parent(v.partial_val.second_arg, interp, target);
1245→            interp.current_frame = target;
1246→        }
1247→        case CONTINUATION:
1248→            // Shallow copy: Value wrapper may be in child scope, cont_val itself is in root_region
1249→            result = interp.alloc_value();
1250→            result.tag = CONTINUATION;
1251→            result.cont_val = v.cont_val;
1252→        case HASHMAP:
1253→        case ARRAY:
1254→        case INSTANCE:
1255→        case METHOD_TABLE:
1256→            result = v;  // Value allocated in root_region; backing data is malloc'd with registered destructors
1257→        case FFI_HANDLE:
1258→            result = v;  // FfiHandle is inline in Value; Value allocated in root_region
1259→        case TYPE_INFO:
1260→            result = v;  // type info lives in registry
1261→        case ITERATOR: {
1262→            // Phase 4b: iterator_val is a Value* to a CLOSURE that may be in a child scope.
1263→            // Promote the underlying closure too so it outlives the ITERATOR.
1264→            interp.current_frame = saved;
1265→            Value* promoted_thunk = copy_to_parent(v.iterator_val, interp, target);
1266→            interp.current_frame = target;
1267→            result = interp.alloc_value();
1268→            result.tag = ITERATOR;
1269→            result.iterator_val = promoted_thunk;
1270→        }
1271→        case FIBER:
1272→            // Shallow copy: Value wrapper may be in child scope, fiber_val (Coro*) managed by stack pool
1273→            result = interp.alloc_value();
1274→            result.tag = FIBER;
1275→            result.fiber_val = v.fiber_val;
1276→        case MODULE:
1277→            result = v;  // Module lives in interp.modules array
1278→        case ERROR:
1279→            result = make_error(interp, v.str_val.chars[:v.str_val.len]);
