2095→/**
2096→ * Run a complete program.
2097→ */
2098→fn EvalResult run_program(char[] source, Interp* interp) {
2099→    Lexer lex;
2100→    lex.init(source);
2101→    Parser p;
2102→    p.init(&lex, interp);
2103→
2104→    List{Expr*} exprs;
2105→    while (!lex.at_end() && !p.has_error) {
2106→        exprs.push(p.parse_expr());
2107→    }
2108→
2109→    if (p.has_error) {
2110→        exprs.free();
2111→        EvalResult r;
2112→        r.value = null;
2113→        r.error.has_error = true;
2114→        r.error.line = p.error_line;
2115→        r.error.column = p.error_col;
2116→        usz len = p.error_msg_len;
2117→        if (len > 255) len = 255;
2118→        for (usz i = 0; i < len; i++) {
2119→            r.error.message[i] = p.error_msg[i];
2120→        }
2121→        r.error.message[len] = 0;
2122→        return r;
2123→    }
2124→
2125→    EvalResult result = eval_ok(make_nil(interp));
2126→
2127→    foreach (expr : exprs) {
2128→        // GC JIT states between top-level expressions (safe: no JIT code on stack)
2129→        jit_gc();
2130→
2131→        // Expand macros before JIT compilation
2132→        expr = expand_macros_in_expr(expr, interp);
2133→        JitFn f = jit_compile(expr, interp);
2134→        if (f != null) {
2135→            Value* jit_result = jit_exec(f, interp);
2136→            if (jit_result != null && jit_result.tag == ERROR) {
2137→                result = eval_error_expr(jit_result.str_val.chars[:jit_result.str_val.len], expr);
2138→            } else {
2139→                result = eval_ok(jit_result);
2140→            }
2141→            if (result.error.has_error) break;
2142→            continue;
2143→        }
2144→        result = eval_error_expr("JIT compilation failed", expr);
2145→        break;
2146→    }
2147→
2148→    exprs.free();
2149→    return result;
2150→}
