2155→fn EvalResult run(char[] source, Interp* interp) {
2156→    Lexer lex;
2157→    lex.init(source);
2158→    Parser p;
2159→    p.init(&lex, interp);
2160→
2161→    Expr* expr = p.parse_expr();
2162→
2163→    if (p.has_error) {
2164→        EvalResult r;
2165→        r.value = null;
2166→        r.error.has_error = true;
2167→        r.error.line = p.error_line;
2168→        r.error.column = p.error_col;
2169→        usz len = p.error_msg_len;
2170→        if (len > 255) len = 255;
2171→        for (usz i = 0; i < len; i++) {
2172→            r.error.message[i] = p.error_msg[i];
2173→        }
2174→        r.error.message[len] = 0;
2175→        return r;
2176→    }
2177→
2178→    // JIT path: compile + execute in child region + child scope
2179→    expr = expand_macros_in_expr(expr, interp);
2180→
2181→    // Push temp frame (old region system)
2182→    main::RegionHandle saved_frame = interp.current_frame;
2183→    interp.current_frame = main::create_region(saved_frame);
2184→
2185→    // Push child scope — temporaries freed after eval
2186→    main::ScopeRegion* saved_scope = interp.current_scope;
2187→    main::ScopeRegion* child_scope = main::scope_create(saved_scope);
2188→    interp.current_scope = child_scope;
2189→
2190→    JitFn f = jit_compile(expr, interp);
2191→    EvalResult result;
2192→    if (f != null) {
2193→        Value* jit_result = jit_exec(f, interp);
2194→        if (jit_result != null && jit_result.tag == ERROR) {
2195→            result = eval_error_expr(jit_result.str_val.chars[:jit_result.str_val.len], expr);
2196→        } else {
2197→            if (jit_result != null) {
2198→                // Promote result to parent scope before releasing child
2199→                interp.current_scope = saved_scope;
2200→                jit_result = copy_to_parent(jit_result, interp, saved_frame);
2201→            }
2202→            result = eval_ok(jit_result);
2203→        }
2204→    } else {
2205→        result = eval_error_expr("JIT compilation failed", expr);
2206→    }
2207→
2208→    // Pop child scope — frees all temporaries from this eval
2209→    interp.current_scope = saved_scope;
2210→    main::scope_release(child_scope);
2211→
2212→    // Pop temp frame (old region system)
2213→    main::release_region(interp.current_frame);
2214→    interp.current_frame = saved_frame;
2215→    return result;
2216→}
