2515→    char* history_file = ".omni_history";
2516→    replxx_history_load(rx, history_file);
2517→
2518→    // ANSI color codes for output
2519→    char[] ansi_red     = "\x1b[31m";
2520→    char[] ansi_green   = "\x1b[32m";
2521→    char[] ansi_reset   = "\x1b[0m";
2522→
2523→    io::printn("Omni Lisp REPL (type 'quit' or 'exit' to leave, Ctrl-D for EOF)");
2524→    io::printn("---");
2525→
2526→    // Buffer for accumulating multi-line input
2527→    char[8192] buf;
2528→    usz buf_len = 0;
2529→
2530→    while (true) {
2531→        // Determine prompt: primary or continuation
2532→        char* prompt;
2533→        if (buf_len == 0) {
2534→            prompt = "\x1b[1;34momni>\x1b[0m ";
2535→        } else {
2536→            prompt = "\x1b[1;34m ....\x1b[0m ";
2537→        }
2538→
2539→        // Use replxx for line editing with syntax highlighting
