2564→            io::printn("Input cancelled.");
2565→            buf_len = 0;
2566→            continue;
2567→        }
2568→
2569→        // Skip empty lines on primary prompt (don't add to history)
2570→        if (buf_len == 0 && len == 0) {
2571→            continue;
2572→        }
2573→
2574→        // Check for quit/exit on primary prompt only
2575→        if (buf_len == 0) {
