2275→fn void Interp.grow_macro_table(Interp* self) {
2276→    usz new_cap = self.macro_capacity * 2;
2277→    MacroDef* new_table = (MacroDef*)mem::malloc(MacroDef.sizeof * new_cap);
2278→    for (usz i = 0; i < self.macro_count; i++) new_table[i] = self.macro_table[i];
2279→    mem::free(self.macro_table);
2280→    self.macro_table = new_table;
2281→    self.macro_capacity = new_cap;
2282→
2283→    // Rebuild hash
2284→    usz new_hash_cap = new_cap * 2;
2285→    usz* new_hash = (usz*)mem::malloc(usz.sizeof * new_hash_cap);
2286→    for (usz i = 0; i < new_hash_cap; i++) new_hash[i] = usz.max;
2287→    mem::free(self.macro_hash_index);
2288→    self.macro_hash_index = new_hash;
2289→    self.macro_hash_capacity = new_hash_cap;
2290→
2291→    usz mask = new_hash_cap - 1;
2292→    for (usz i = 0; i < self.macro_count; i++) {
2293→        char[] name_str = self.symbols.get_name(self.macro_table[i].name);
2294→        usz h = hash_symbol(name_str);
2295→        for (usz probe = 0; probe < new_hash_cap; probe++) {
2296→            usz slot = (h + probe) & mask;
2297→            if (new_hash[slot] == usz.max) {
2298→                new_hash[slot] = i;
2299→                break;
2300→            }
2301→        }
2302→    }
2303→}
