 895→/**
 896→ * raise_error — Recoverable error via algebraic effect system.
 897→ *
 898→ * If a `raise` handler is on the handler stack, sets raise_pending flag and
 899→ * returns V_ERROR for stack unwinding. If no handler, falls back to V_ERROR
 900→ * (same as make_error).
 901→ *
 902→ * Use make_error() for fatal/internal errors only (stack overflow, invariants).
 903→ */
 904→fn Value* raise_error(Interp* interp, char[] msg) {
 905→    // Fast path: no handlers at all → just return error
 906→    if (interp.handler_count == 0) {
 907→        return make_error(interp, msg);
 908→    }
 909→
 910→    // If a raise is already pending, don't overwrite it (error re-propagation)
 911→    if (interp.flags.raise_pending) {
 912→        return make_error(interp, msg);
 913→    }
 914→
 915→    SymbolId raise_sym = interp.sym_raise;
 916→
 917→    // Search handler stack from top (most recent) to bottom
 918→    for (isz i = (isz)interp.handler_count - 1; i >= 0; i--) {
 919→        EffectHandler* h = &interp.handler_stack[(usz)i];
 920→
 921→        for (usz j = 0; j < h.clause_count; j++) {
 922→            if ((uint)h.clauses[j].effect_tag == (uint)raise_sym) {
 923→                // Found a raise handler — set pending flag for jit_handle_impl to dispatch.
 924→                // We can't safely call jit_eval from within a primitive call chain,
 925→                // so we store the message and let the handle block dispatch.
 926→                interp.flags.raise_pending = true;
 927→                usz copy_len = msg.len;
 928→                if (copy_len > 255) copy_len = 255;
 929→                for (usz ci = 0; ci < copy_len; ci++) interp.raise_msg[ci] = msg[ci];
 930→                interp.raise_msg[copy_len] = 0;
 931→                interp.raise_msg_len = copy_len;
 932→                return make_error(interp, msg);
 933→            }
 934→        }
 935→
 936→        if (h.strict_mode) break;
 937→    }
 938→
 939→    // No raise handler found — fall back to V_ERROR
 940→    return make_error(interp, msg);
 941→}
