355→// Scope-per-call wrapper: evaluates closure body in a child scope.
356→// Temporaries from the body (CONS cells, format buffers, etc.) are freed per call.
357→// TCO scope recycling may replace the call_scope during jit_eval's trampoline,
358→// so we capture interp.current_scope after jit_eval returns (not the original).
359→fn Value* jit_eval_in_call_scope(Expr* body, Env* call_env, Interp* interp) {
360→    main::ScopeRegion* saved_scope = interp.current_scope;
361→    main::ScopeRegion* call_scope = main::scope_create(saved_scope);
362→    interp.current_scope = call_scope;
363→
364→    // Mark this scope as eligible for TCO recycling
365→    main::ScopeRegion* saved_recycle = interp.tco_recycle_scope;
366→    interp.tco_recycle_scope = call_scope;
367→
368→    Value* result = jit_eval(body, call_env, interp);
369→
370→    // After jit_eval, current_scope may differ from call_scope (TCO recycling)
371→    main::ScopeRegion* active_scope = interp.current_scope;
372→
373→    // Restore recycle scope eligibility
374→    interp.tco_recycle_scope = saved_recycle;
375→
376→    // Promote result to caller's scope before releasing
377→    interp.current_scope = saved_scope;
378→    if (result != null) {
379→        result = copy_to_parent(result, interp, interp.current_frame);
380→    }
381→
382→    // Release the scope that jit_eval was using (may be call_scope or a TCO replacement)
383→    main::scope_release(active_scope);
384→
385→    return result;
386→}
