482→// Lambda/closure creation helper — called from JIT-compiled code.
483→// Mirrors eval_lambda from eval.c3: creates a closure value from an E_LAMBDA Expr*.
484→// Phase 4b: Closures allocated in current_scope (not root_scope). Env copied to a
485→// standalone env_scope (refcounted). Temporary closures freed when scope releases.
486→fn Value* jit_make_closure_from_expr(Interp* interp, Expr* expr, Env* env) {
487→    main::ScopeRegion* creation_scope = interp.current_scope;
488→    bool need_env_copy = (creation_scope != interp.root_scope ||
489→                          interp.current_frame.region_id != interp.root_region.region_id);
490→
491→    // Check for zero-arg lambda (sentinel param)
492→    if ((uint)expr.lambda.param == 0xFFFFFFFF && !expr.lambda.has_rest) {
493→        Value* closure = make_closure_no_param(interp, expr.lambda.body, env);
494→        if (need_env_copy) {
495→            main::ScopeRegion* env_scope = main::scope_create(null);
496→            interp.current_scope = env_scope;
497→            closure.closure_val.env = copy_env_to_scope(env, interp);
498→            closure.closure_val.env_scope = env_scope;
499→            interp.current_scope = creation_scope;
500→        }
501→        return closure;
502→    }
503→
504→    // Create closure in current_scope
505→    Value* closure = make_closure(interp, expr.lambda.param, expr.lambda.body, env);
506→
507→    // Copy variadic info from ExprLambda to Closure
508→    closure.closure_val.param_count = expr.lambda.param_count;
509→    if (expr.lambda.param_count > 0) {
510→        mem::free(closure.closure_val.params);
511→        closure.closure_val.params = (SymbolId*)mem::malloc(SymbolId.sizeof * expr.lambda.param_count);
512→        for (usz i = 0; i < expr.lambda.param_count; i++) {
513→            closure.closure_val.params[i] = expr.lambda.params[i];
514→        }
515→    }
516→    closure.closure_val.has_rest = expr.lambda.has_rest;
517→    closure.closure_val.rest_param = expr.lambda.rest_param;
518→
519→    // For variadic with zero fixed params: (lambda (.. args) body)
520→    if (expr.lambda.has_rest && expr.lambda.param_count == 0) {
521→        closure.closure_val.has_param = false;
522→        closure.closure_val.param = 0;
523→    }
524→
525→    // Build type signature if lambda has typed params
526→    closure.closure_val.has_typed_params = expr.lambda.has_typed_params;
527→    closure.closure_val.type_sig = null;
528→    if (expr.lambda.has_typed_params) {
529→        MethodSignature* sig = (MethodSignature*)mem::malloc(MethodSignature.sizeof);
530→        sig.param_count = expr.lambda.param_count;
531→        sig.constraint_count = 0;
532→        usz ann_count = expr.lambda.param_count;
533→        if (ann_count > 8) ann_count = 8;
534→        for (usz i = 0; i < ann_count; i++) {
535→            TypeAnnotation* ann = &expr.lambda.param_annotations[i];
536→            if (ann.has_annotation) {
537→                if (ann.has_val_literal) {
538→                    sig.param_types[i] = INVALID_TYPE_ID;
539→                    sig.val_literals[i] = ann.val_literal;
540→                    sig.has_val_literal[i] = true;
541→                } else if (ann.is_dict) {
542→                    sig.param_types[i] = INVALID_TYPE_ID;
543→                    sig.has_val_literal[i] = false;
544→                    for (usz m = 0; m < ann.meta_count && sig.constraint_count < MAX_TYPE_PARAMS; m++) {
545→                        if (!ann.meta[m].is_int) {
546→                            sig.constraints[sig.constraint_count].param_sym = ann.meta[m].key;
547→                            sig.constraints[sig.constraint_count].bound_type =
548→                                interp.types.lookup(ann.meta[m].sym_value, &interp.symbols);
549→                            sig.constraint_count++;
550→                        }
551→                    }
552→                } else {
553→                    sig.param_types[i] = interp.types.lookup(ann.base_type, &interp.symbols);
554→                    sig.has_val_literal[i] = false;
555→                }
556→            } else {
557→                sig.param_types[i] = INVALID_TYPE_ID;
558→                sig.has_val_literal[i] = false;
559→            }
560→        }
561→        closure.closure_val.type_sig = sig;
562→    }
563→
564→    // Copy env to standalone env_scope if in a non-root scope/frame
565→    if (need_env_copy) {
566→        main::ScopeRegion* env_scope = main::scope_create(null);
567→        interp.current_scope = env_scope;
568→        closure.closure_val.env = copy_env_to_scope(env, interp);
569→        closure.closure_val.env_scope = env_scope;
570→        interp.current_scope = creation_scope;
571→    }
572→
573→    return closure;
574→}
