576→// Recursive let helper — called from JIT-compiled code.
577→// Mirrors the is_recursive branch of eval_let from eval.c3.
578→// Creates placeholder, extends env, evaluates init, patches closure, evaluates body.
579→fn Value* jit_eval_let_rec(Interp* interp, Expr* expr, Env* env) {
580→    // 1. Create placeholder
581→    Value* placeholder = make_nil(interp);
582→
583→    // 2. Extend env with name bound to placeholder
584→    Env* rec_env = env.extend(interp, expr.let_expr.name, placeholder);
585→
586→    // 3. JIT-compile init in the extended env (so it can reference itself)
587→    Value* actual_value = jit_eval(expr.let_expr.init, rec_env, interp);
588→    if (actual_value != null && actual_value.tag == ERROR) return actual_value;
589→
590→    // 4. Patch: if closure, create self-reference in its env
591→    if (is_closure(actual_value)) {
592→        if (actual_value.closure_val.env_scope != null) {
593→            // Non-root closure: create weak self-reference in env_scope.
594→            // "Weak" means no refcount bump and no dtor — breaks the RC cycle
595→            // (closure→env→self_ref→closure). Safe because self_ref is only
596→            // accessed during body evaluation while the Closure is alive.
597→            main::ScopeRegion* saved_scope = interp.current_scope;
598→            interp.current_scope = actual_value.closure_val.env_scope;
599→            Value* self_ref = interp.alloc_value();
600→            self_ref.tag = CLOSURE;
601→            self_ref.closure_val = actual_value.closure_val;
602→            // NO refcount bump — weak reference
603→            // NO dtor registration — just data in env_scope chunks
604→            interp.current_scope = saved_scope;
605→
606→            // Patch self-reference in the COPIED env (inside env_scope)
607→            Env* closure_env = actual_value.closure_val.env;
608→            for (usz i = 0; i < closure_env.binding_count; i++) {
609→                if ((uint)closure_env.bindings[i].name == (uint)expr.let_expr.name) {
610→                    closure_env.bindings[i].value = self_ref;
611→                    break;
612→                }
613→            }
614→        } else {
615→            // Root-scope closure: direct assignment (permanent, no copy needed)
616→            actual_value.closure_val.env = rec_env;
617→        }
618→    }
619→
620→    // Update placeholder binding in rec_env
621→    for (usz i = 0; i < rec_env.binding_count; i++) {
622→        if ((uint)rec_env.bindings[i].name == (uint)expr.let_expr.name) {
623→            rec_env.bindings[i].value = actual_value;
624→            break;
625→        }
626→    }
627→
628→    // 5. Evaluate body in its own call scope.
629→    // Named-let desugars to (let ^rec (loop (lambda ...)) (loop init...)).
630→    // The body (loop init...) triggers TCO bounces for the loop iterations.
631→    // Using jit_eval_in_call_scope gives each named-let its own scope, so
632→    // nested named-lets (e.g., flatten's loop calling loop2) don't recycle
633→    // the outer loop's scope — each loop's tco_recycle_scope is independent.
634→    return jit_eval_in_call_scope(expr.let_expr.body, rec_env, interp);
635→}
