637→// set! helper — called from JIT-compiled code.
638→// Evaluates to the set value, mirrors E_SET in eval().
639→fn Value* jit_eval_set(Interp* interp, SymbolId name, Value* value, Env* env) {
640→    // When in child scope/frame, promote value to root so it survives scope release.
641→    // Env bindings (closures, globals) live in root scope; storing a child-scope
642→    // value would create a dangling pointer.
643→    Value* stored = value;
644→    if (interp.current_scope != interp.root_scope || interp.current_frame.region_id != interp.root_region.region_id) {
645→        main::ScopeRegion* saved_scope_ctp = interp.current_scope;
646→        interp.current_scope = interp.root_scope;
647→        stored = copy_to_parent(value, interp, interp.root_region);
648→        interp.current_scope = saved_scope_ctp;
649→    }
650→    // Try local env first, then global
651→    if (!env.set(name, stored)) {
652→        if (interp.global_env == null || !interp.global_env.set(name, stored)) {
653→            return raise_error(interp, "set!: unbound variable");
654→        }
655→    }
656→    return stored;
657→}
