659→// set! dot-path helper — handles (set! obj.field value) mutations.
660→// Mirrors the dot-path E_SET logic from eval.c3 lines 496-561.
661→fn Value* jit_eval_set_path(Interp* interp, Expr* expr, Value* value, Env* env) {
662→    // Resolve root object
663→    Value* current = env.lookup(expr.set_expr.path_segments[0]);
664→    if (current == null) current = interp.global_env.lookup(expr.set_expr.path_segments[0]);
665→    if (current == null) return raise_error(interp, "set!: unbound path root");
666→
667→    // Traverse intermediate segments
668→    for (usz si = 1; si < expr.set_expr.path_segment_count - 1; si++) {
669→        if (current != null && current.tag == INSTANCE && current.instance_val != null) {
670→            TypeInfo* ti = interp.types.get(current.instance_val.type_id);
671→            bool found = false;
672→            if (ti != null) {
673→                for (usz fi = 0; fi < ti.field_count; fi++) {
674→                    if (ti.fields[fi].name == expr.set_expr.path_segments[si]) {
675→                        if (fi < current.instance_val.field_count) {
676→                            current = current.instance_val.fields[fi];
677→                            found = true;
678→                            break;
679→                        }

680→                    }
681→                }
682→            }
683→            if (!found) return raise_error(interp, "set!: field not found in path");
684→        } else if (current != null && current.tag == CONS) {
685→            SymbolId seg = expr.set_expr.path_segments[si];
686→            if ((uint)seg == (uint)interp.sym_car) { current = current.cons_val.car; }
687→            else if ((uint)seg == (uint)interp.sym_cdr) { current = current.cons_val.cdr; }
688→            else { return raise_error(interp, "set!: cons only supports .car and .cdr"); }
689→        } else {
690→            return raise_error(interp, "set!: path segment is not an instance or cons");
691→        }
692→    }
693→
694→    // Mutate the last field
695→    SymbolId last_seg = expr.set_expr.path_segments[expr.set_expr.path_segment_count - 1];
696→
697→    // Promote value to root scope — cons cells and instances live in root_scope,
698→    // so storing a child-scope value would create a dangling pointer after scope release.
699→    value = promote_to_root(value, interp);
700→
701→    // Cons cell mutation
702→    if (current != null && current.tag == CONS) {
703→        if ((uint)last_seg == (uint)interp.sym_car) {
704→            current.cons_val.car = value;
705→            return value;
706→        }
707→        if ((uint)last_seg == (uint)interp.sym_cdr) {
708→            current.cons_val.cdr = value;
709→            return value;
710→        }
711→        return raise_error(interp, "set!: cons only supports .car and .cdr");
712→    }
713→
714→    // Instance field mutation
715→    if (current != null && current.tag == INSTANCE && current.instance_val != null) {
716→        TypeInfo* ti = interp.types.get(current.instance_val.type_id);
717→        if (ti != null) {
718→            for (usz fi = 0; fi < ti.field_count; fi++) {
719→                if (ti.fields[fi].name == last_seg) {
720→                    if (fi < current.instance_val.field_count) {
721→                        current.instance_val.fields[fi] = value;
722→                        return value;
723→                    }
724→                }
725→            }
726→        }
727→        return raise_error(interp, "set!: field not found");
728→    }
729→    return raise_error(interp, "set!: target is not an instance or cons");
730→}
