732→// define helper — called from JIT-compiled code.
733→// Full define with typed dispatch support, mirrors eval_define from eval.c3.
734→<* @require interp != null : "jit_eval_define: null interp"
735→   @require value != null : "jit_eval_define: null value" *>
736→fn Value* jit_eval_define(Interp* interp, SymbolId name, Value* value) {
737→    // Copy to root scope/region for globals (so value survives scope release)
738→    Value* stored_val = value;
739→    if (interp.current_scope != interp.root_scope || interp.current_frame.region_id != interp.root_region.region_id) {
740→        main::ScopeRegion* saved_scope_ctp = interp.current_scope;
741→        interp.current_scope = interp.root_scope;
742→        stored_val = copy_to_parent(value, interp, interp.root_region);
743→        interp.current_scope = saved_scope_ctp;
744→    }
745→
746→    // Check for typed closure → method table dispatch
747→    if (stored_val != null && stored_val.tag == CLOSURE && stored_val.closure_val.has_typed_params) {
748→        Value* existing = interp.global_env.lookup(name);
749→        if (existing != null && existing.tag == METHOD_TABLE) {
750→            MethodTable* mt = existing.method_table_val;
751→            // Grow entries array if needed
752→            if (mt.entry_count >= mt.capacity) {
753→                usz new_cap = mt.capacity * 2;
754→                MethodEntry* new_entries = (MethodEntry*)mem::malloc(MethodEntry.sizeof * new_cap);
755→                for (usz ei = 0; ei < mt.entry_count; ei++) new_entries[ei] = mt.entries[ei];
756→                mem::free(mt.entries);
757→                mt.entries = new_entries;
758→                mt.capacity = new_cap;
759→            }
760→            mt.entries[mt.entry_count].sig = *stored_val.closure_val.type_sig;
761→            mt.entries[mt.entry_count].implementation = stored_val;
762→            mt.entry_count++;
763→            return existing;
764→        } else if (existing != null && existing.tag == CLOSURE) {
765→            MethodTable* mt = (MethodTable*)mem::malloc(MethodTable.sizeof);
766→            mt.name = name;
767→            mt.entries = (MethodEntry*)mem::malloc(MethodEntry.sizeof * METHOD_INITIAL_CAPACITY);
768→            mt.capacity = METHOD_INITIAL_CAPACITY;
769→            mt.entry_count = 0;
770→            mt.fallback = existing;
771→            mt.entries[0].sig = *stored_val.closure_val.type_sig;
772→            mt.entries[0].implementation = stored_val;
773→            mt.entry_count = 1;
774→            main::RegionHandle saved_mt = interp.current_frame;
775→            interp.current_frame = interp.root_region;
776→            main::ScopeRegion* saved_mt_scope = interp.current_scope;
777→            interp.current_scope = interp.root_scope;
778→            Value* mt_val = interp.alloc_value();
779→            main::scope_register_dtor(interp.root_scope, (void*)mt_val, &scope_dtor_value);
780→            interp.current_scope = saved_mt_scope;
781→            interp.current_frame = saved_mt;
782→            mt_val.tag = METHOD_TABLE;
783→            mt_val.method_table_val = mt;
784→
785→            interp.global_env.define(name, mt_val);
786→            return mt_val;
787→        } else if (existing != null && existing.tag == PRIMITIVE) {
788→            MethodTable* mt = (MethodTable*)mem::malloc(MethodTable.sizeof);
789→            mt.name = name;
790→            mt.entries = (MethodEntry*)mem::malloc(MethodEntry.sizeof * METHOD_INITIAL_CAPACITY);
791→            mt.capacity = METHOD_INITIAL_CAPACITY;
792→            mt.entry_count = 0;
793→            mt.fallback = existing;
794→            mt.entries[0].sig = *stored_val.closure_val.type_sig;
795→            mt.entries[0].implementation = stored_val;
796→            mt.entry_count = 1;
797→            main::RegionHandle saved_mt = interp.current_frame;
798→            interp.current_frame = interp.root_region;
799→            main::ScopeRegion* saved_mt_scope = interp.current_scope;
800→            interp.current_scope = interp.root_scope;
801→            Value* mt_val = interp.alloc_value();
802→            main::scope_register_dtor(interp.root_scope, (void*)mt_val, &scope_dtor_value);
803→            interp.current_scope = saved_mt_scope;
804→            interp.current_frame = saved_mt;
805→            mt_val.tag = METHOD_TABLE;
806→            mt_val.method_table_val = mt;
807→
808→            interp.global_env.define(name, mt_val);
809→            return mt_val;
810→        } else {
811→            MethodTable* mt = (MethodTable*)mem::malloc(MethodTable.sizeof);
812→            mt.name = name;
813→            mt.entries = (MethodEntry*)mem::malloc(MethodEntry.sizeof * METHOD_INITIAL_CAPACITY);
814→            mt.capacity = METHOD_INITIAL_CAPACITY;
815→            mt.entries[0].sig = *stored_val.closure_val.type_sig;
816→            mt.entries[0].implementation = stored_val;
817→            mt.entry_count = 1;
818→            mt.fallback = null;
819→            main::RegionHandle saved_mt = interp.current_frame;
820→            interp.current_frame = interp.root_region;
821→            main::ScopeRegion* saved_mt_scope = interp.current_scope;
822→            interp.current_scope = interp.root_scope;
823→            Value* mt_val = interp.alloc_value();
824→            main::scope_register_dtor(interp.root_scope, (void*)mt_val, &scope_dtor_value);
825→            interp.current_scope = saved_mt_scope;
826→            interp.current_frame = saved_mt;
827→            mt_val.tag = METHOD_TABLE;
828→            mt_val.method_table_val = mt;
829→
830→            interp.global_env.define(name, mt_val);
831→            return mt_val;
832→        }
833→    }
834→
835→    // Check if we're adding an untyped fallback to an existing method table
836→    Value* existing_for_fallback = interp.global_env.lookup(name);
837→    if (existing_for_fallback != null && existing_for_fallback.tag == METHOD_TABLE) {
838→        existing_for_fallback.method_table_val.fallback = stored_val;
839→        return existing_for_fallback;
840→    }
841→
842→    // Tag closure with its bound name for display
843→    if (stored_val != null && stored_val.tag == CLOSURE) {
844→        stored_val.closure_val.name = name;
845→    }
846→
847→    // Normal (untyped) define
848→    interp.global_env.define(name, stored_val);
849→    return stored_val;
850→}
