863→fn Env* jit_env_extend_root(Interp* interp, Env* env, SymbolId name, Value* value) {
864→    main::RegionHandle saved = interp.current_frame;
865→    interp.current_frame = interp.root_region;
866→    main::ScopeRegion* saved_scope = interp.current_scope;
867→    interp.current_scope = interp.root_scope;
