1079→/**
1080→ * Fiber-based reset: runs body on a separate stack (coroutine).
1081→ *
1082→ * If the body completes normally, returns its value.
1083→ * If the body calls (shift k BODY), the coro suspends and BODY is
1084→ * evaluated in the parent context with k bound to the suspended coro.
1085→ * The shift body's return value becomes the reset's return value.
1086→ */
1087→fn EvalResult jit_reset_impl_fiber(Expr* expr, Env* env, Interp* interp) {
1088→    main::Coro* coro = main::coro_create(&interp.coro_pool);
1089→    if (coro == null) return eval_error("stack engine: failed to create coro for reset");
1090→
1091→    ResetCoroState state;
1092→    state.body = expr.reset.body;
1093→    state.env = env;
1094→    state.interp = interp;
1095→    state.shifted = false;
1096→    state.shift_body = null;
1097→    state.shift_env = null;
1098→
1099→    main::coro_init(coro, &reset_coro_entry, &state);
1100→
1101→    // Save/restore the reset state pointer for nesting
1102→    void* saved_state = interp.current_reset_state;
1103→    interp.current_reset_state = &state;
1104→
1105→    // Save interp state before entering coro. The coro shares the same Interp
1106→    // and its jit_eval calls modify these fields (eval_depth, jit_env, etc.).
1107→    // When the coro suspends (shift) or completes, these are left in the coro's
1108→    // state. We must restore the parent's values.
1109→    Env*        saved_jit_env       = interp.jit_env;
1110→    Env*        saved_match_env     = interp.match_env;
1111→    usz         saved_eval_depth    = interp.eval_depth;
1112→    InterpFlags saved_flags         = interp.flags;
1113→    Expr*       saved_tco_expr      = interp.jit_tco_expr;
1114→    Env*        saved_tco_env       = interp.jit_tco_env;
1115→    main::ScopeRegion* saved_tco_recycle = interp.tco_recycle_scope;
1116→    usz         saved_reset_depth   = interp.reset_depth;
1117→    usz         saved_handler_count = interp.handler_count;
1118→    main::ScopeRegion* saved_coro_scope = interp.current_scope;
1119→
1120→    // Run the coroutine
1121→    main::StackContext parent_ctx;
1122→    main::coro_switch_to(coro, &parent_ctx);
1123→
1124→    // Restore interp state after coro suspends/completes
1125→    interp.current_reset_state = saved_state;
1126→    interp.jit_env        = saved_jit_env;
1127→    interp.match_env      = saved_match_env;
1128→    interp.eval_depth     = saved_eval_depth;
1129→    interp.flags          = saved_flags;
1130→    interp.jit_tco_expr   = saved_tco_expr;
1131→    interp.jit_tco_env    = saved_tco_env;
1132→    interp.tco_recycle_scope = saved_tco_recycle;
1133→    interp.reset_depth    = saved_reset_depth;
1134→    interp.handler_count  = saved_handler_count;
1135→    interp.current_scope  = saved_coro_scope;
1136→
1137→    // Stack overflow — coro hit guard page
1138→    if (coro.status == main::CoroStatus.CORO_DEAD) {
1139→        main::coro_destroy(coro, &interp.coro_pool);
1140→        return eval_error("stack overflow in reset body");
1141→    }
1142→
1143→    if (state.shifted) {
1144→        // Shift occurred — evaluate shift body in parent context
1145→        Value* shift_result = jit_eval(state.shift_body, state.shift_env, interp);
1146→        if (shift_result != null && shift_result.tag == ERROR) {
1147→            return eval_error(shift_result.str_val.chars[:shift_result.str_val.len]);
1148→        }
1149→        return eval_ok(shift_result);
1150→    }
1151→
1152→    // Normal completion (no shift)
1153→    Value* v = (Value*)coro.result;
1154→    main::coro_destroy(coro, &interp.coro_pool);
1155→    if (v != null && v.tag == ERROR) {
1156→        return eval_error(v.str_val.chars[:v.str_val.len]);
1157→    }
1158→    return eval_ok(v);
1159→}
