1161→/**
1162→ * Fiber-based shift: suspends the current coroutine and creates a continuation.
1163→ *
1164→ * This function is called INSIDE a coroutine (created by jit_reset_impl_fiber).
1165→ * It captures the current coro as a continuation, stores the shift body info
1166→ * in the parent's ResetCoroState, and suspends. When resumed by (k val),
1167→ * it returns the resume value.
1168→ */
1169→fn Value* jit_shift_impl_fiber(Expr* expr, Env* env, Interp* interp) {
1170→    // IMPORTANT: Returns Value* (not EvalResult) so the return fits in RAX.
1171→    // EvalResult is >16 bytes, triggering the System V ABI hidden return pointer.
1172→    // After coro_clone that pointer is stale, causing writes to the wrong stack.
1173→    main::Coro* current = main::g_current_coro;
1174→    if (current == null) {
1175→        return make_error(interp, "shift outside of reset");
1176→    }
1177→
1178→    ResetCoroState* rstate = (ResetCoroState*)interp.current_reset_state;
1179→    if (rstate == null) {
1180→        return make_error(interp, "shift outside of reset (no reset state)");
1181→    }
1182→
1183→    // Create continuation wrapping the current coro
1184→    Continuation* k = interp.alloc_lisp_continuation();
1185→    k.coro = current;
1186→    k.is_fiber_based = true;
1187→
1188→    Value* k_val = make_continuation(interp, k);
1189→
1190→    // Bind k in the shift body's environment
1191→    Env* shift_env = env.extend(interp, expr.shift.k_name, k_val);
1192→
1193→    // Store shift body info for the parent (jit_reset_impl_fiber) to evaluate
1194→    rstate.shifted = true;
1195→    rstate.shift_body = expr.shift.body;
1196→    rstate.shift_env = shift_env;
1197→
1198→    // Save interpreter state that the parent's evaluation will corrupt.
1199→    // These are effectively "callee-saved registers" of the interpreter —
1200→    // the coro's evaluation expects them to be preserved across the suspend.
1201→    // The parent shares the same Interp but modifies these fields when
1202→    // evaluating the shift body. We must restore them on resume.
1203→    Env*       saved_jit_env    = interp.jit_env;
1204→    Env*       saved_match_env  = interp.match_env;
1205→    usz        saved_eval_depth = interp.eval_depth;
1206→    InterpFlags saved_flags     = interp.flags;
1207→    Expr*      saved_tco_expr   = interp.jit_tco_expr;
1208→    Env*       saved_tco_env    = interp.jit_tco_env;
1209→    main::ScopeRegion* saved_tco_recycle = interp.tco_recycle_scope;
1210→    usz        saved_reset_depth = interp.reset_depth;
1211→    usz        saved_handler_count = interp.handler_count;
1212→    main::ScopeRegion* saved_coro_scope = interp.current_scope;
1213→
1214→    // Suspend the coro — control returns to jit_reset_impl_fiber
1215→    main::coro_suspend();
1216→
1217→    // === RESUMED HERE by (k val) via jit_apply_fiber_continuation ===
1218→    // Restore interpreter state (corrupted by parent's evaluation of shift body)
1219→    interp.jit_env = saved_jit_env;
1220→    interp.match_env = saved_match_env;
1221→    interp.eval_depth = saved_eval_depth;
1222→    interp.flags = saved_flags;
1223→    interp.jit_tco_expr = saved_tco_expr;
1224→    interp.jit_tco_env = saved_tco_env;
1225→    interp.tco_recycle_scope = saved_tco_recycle;
1226→    interp.reset_depth = saved_reset_depth;
1227→    interp.handler_count = saved_handler_count;
1228→    interp.current_scope = saved_coro_scope;
1229→
1230→    return interp.resume_value;
1231→}
