1233→/**
1234→ * Apply a fiber-based continuation: clone the coro and resume it.
1235→ *
1236→ * Always clones for multi-shot safety — the original stays suspended
1237→ * as a "template" for potential future invocations.
1238→ */
1239→fn EvalResult jit_apply_fiber_continuation(Value* k_val, Value* arg, Interp* interp) {
1240→    main::Coro* coro = k_val.cont_val.coro;
1241→
1242→    if (coro == null) {
1243→        return eval_error("cannot resume continuation: null coro");
1244→    }
1245→    if (coro.status == main::CoroStatus.CORO_COMPLETED || coro.status == main::CoroStatus.CORO_DEAD) {
1246→        return eval_error("cannot resume completed/dead continuation");
1247→    }
1248→    if (coro.status != main::CoroStatus.CORO_SUSPENDED) {
1249→        return eval_error("cannot resume running continuation");
1250→    }
1251→
1252→    // Clone for multi-shot safety (original stays suspended as template)
1253→    main::Coro* target = main::coro_clone(coro, &interp.coro_pool);
1254→    if (target == null) {
1255→        return eval_error("stack engine: failed to clone coro for continuation");
1256→    }
1257→
1258→    // Pass the resume value to the shift function
1259→    interp.resume_value = arg;
1260→
1261→    // Set up a reset-like context to catch any shifts in the resumed body
1262→    ResetCoroState resume_state;
1263→    resume_state.shifted = false;
1264→    resume_state.shift_body = null;
1265→    resume_state.shift_env = null;
1266→    resume_state.body = null;
1267→    resume_state.env = null;
1268→    resume_state.interp = interp;
1269→

1350→    EffectHandler  handler_copy;   // Copy of handler for reinstallation by resolve
1351→    usz            handler_idx;    // Handler stack index
1352→}
