1360→/**
1361→ * Fiber-based signal: suspends the current coro when a matching fiber handler is found.
1362→ *
1363→ * Returns Value* directly (same pattern as jit_shift_impl_fiber — avoids the hidden
1364→ * return pointer issue with EvalResult after coro_clone).
1365→ *
1366→ * Falls through to the I/O fast path or error if no fiber handler matches.
1367→ */
1368→fn Value* jit_signal_impl_fiber(Expr* expr, Env* env, Interp* interp) {
1369→    // Evaluate the argument
1370→    Value* arg_v = jit_eval(expr.perform.arg, env, interp);
1371→    if (arg_v != null && arg_v.tag == ERROR) return arg_v;
1372→
1373→    SymbolId tag = expr.perform.tag;
1374→
1375→    // Type check (same as older path)
1376→    TypeId effect_tid = interp.types.lookup(tag, &interp.symbols);
1377→    if (effect_tid != INVALID_TYPE_ID) {
1378→        TypeInfo* effect_info = interp.types.get(effect_tid);
1379→        if (effect_info != null && effect_info.kind == TK_EFFECT && effect_info.field_count > 0) {
1380→            TypeId expected_tid = effect_info.fields[0].field_type;
1381→            if (expected_tid != INVALID_TYPE_ID && expected_tid != interp.tid_Any) {
1382→                TypeId actual_tid = infer_value_type(arg_v, interp);
1383→                if (actual_tid != INVALID_TYPE_ID && !interp.types.is_subtype(actual_tid, expected_tid)) {
1384→                    char[256] ebuf;
1385→                    char[] tag_name = interp.symbols.get_name(tag);
1386→                    TypeInfo* exp_ti = interp.types.get(expected_tid);
1387→                    TypeInfo* act_ti = interp.types.get(actual_tid);
1388→                    char[] exp_name = exp_ti != null ? interp.symbols.get_name(exp_ti.name) : "?";
1389→                    char[] act_name = act_ti != null ? interp.symbols.get_name(act_ti.name) : "?";
1390→                    char[] msg = io::bprintf(&ebuf, "perform '%s': expected %s argument, got %s",
1391→                        (ZString)tag_name, (ZString)exp_name, (ZString)act_name)!!;
1392→                    return make_error(interp, msg);
1393→                }
1394→            }
1395→        }
1396→    }
1397→
1398→    // Search handler stack for a matching fiber handler
1399→    main::Coro* current = main::g_current_coro;
1400→    if (current != null) {
1401→        bool hit_strict = false;
1402→        for (isz i = (isz)interp.handler_count - 1; i >= 0; i--) {
1403→            EffectHandler* h = &interp.handler_stack[(usz)i];
1404→
1405→            for (usz j = 0; j < h.clause_count; j++) {
1406→                if ((uint)h.clauses[j].effect_tag == (uint)tag) {
1407→                    // Found matching handler
1408→                    if (h.fiber_state != null) {
1409→                        // Fiber path: suspend coro, inform handle loop
1410→                        HandleFiberState* hstate = (HandleFiberState*)h.fiber_state;
1411→                        hstate.signaled = true;
1412→                        hstate.signal_tag = tag;
1413→                        hstate.signal_arg = arg_v;
1414→
