1525→/**
1526→ * Fiber-based handle: runs body on a coro, dispatches signals to handler clauses.
1527→ *
1528→ * Signal suspends the coro. The handle loop finds the matching clause, creates
1529→ * a continuation k, and evaluates the clause in the parent context. Resolve
1530→ * resumes the coro (single-shot).
1531→ */
1532→fn EvalResult jit_handle_impl_fiber(Expr* expr, Env* env, Interp* interp) {
1533→    main::Coro* coro = main::coro_create(&interp.coro_pool);
1534→    if (coro == null) return eval_error("stack engine: failed to create coro for handle");
1535→
1536→    HandleFiberState state;
1537→    state.body = expr.handle.body;
1538→    state.env = env;
1539→    state.interp = interp;
1540→    state.signaled = false;
1541→    state.signal_tag = (SymbolId)0;
1542→    state.signal_arg = null;
1543→
1544→    main::coro_init(coro, &handle_fiber_entry, &state);
1545→
1546→    // Push handler on stack
1547→    if (interp.handler_count >= interp.handler_capacity) interp.grow_handler_stack();
1548→    usz my_idx = interp.handler_count;
1549→    EffectHandler* h = &interp.handler_stack[my_idx];
1550→    h.clause_count = expr.handle.clause_count;
1551→    h.handler_env = env;
1552→    h.body_expr = expr.handle.body;
1553→    h.body_env = env;
1554→    h.strict_mode = expr.handle.strict_mode;
1555→    h.fiber_state = &state;
1556→
1557→    // Allocate dynamic arrays for handler clauses
1558→    h.tags = (SymbolId*)mem::malloc(SymbolId.sizeof * expr.handle.clause_count);
1559→    h.clauses = (EffectClause*)mem::malloc(EffectClause.sizeof * expr.handle.clause_count);
1560→    for (usz i = 0; i < expr.handle.clause_count; i++) {
1561→        h.tags[i] = expr.handle.clauses[i].effect_tag;
1562→        h.clauses[i] = expr.handle.clauses[i];
1563→    }
1564→
1565→    interp.handler_count = my_idx + 1;
1566→
1567→    // Save handler copy for reinstallation after clause evaluation
1568→    state.handler_copy = *h;
1569→    state.handler_idx = my_idx;
1570→
1571→    // Save interp state before entering coro
1572→    Env*        saved_jit_env       = interp.jit_env;
1573→    Env*        saved_match_env     = interp.match_env;
1574→    usz         saved_eval_depth    = interp.eval_depth;
1575→    InterpFlags saved_flags         = interp.flags;
1576→    Expr*       saved_tco_expr      = interp.jit_tco_expr;
1577→    Env*        saved_tco_env       = interp.jit_tco_env;
1578→    main::ScopeRegion* saved_tco_recycle = interp.tco_recycle_scope;
1579→    usz         saved_reset_depth   = interp.reset_depth;
1580→    usz         saved_handler_count = interp.handler_count;  // my_idx + 1
1581→    main::ScopeRegion* saved_coro_scope = interp.current_scope;
1582→
1583→    // Run the body on the coro
1584→    main::StackContext parent_ctx;
1585→    main::coro_switch_to(coro, &parent_ctx);
1586→
1587→    // Capture raise_pending before restoring flags (the coro may have set it)
1588→    bool coro_raise_pending = interp.flags.raise_pending;
1589→
1590→    // Restore interp state
1591→    interp.jit_env        = saved_jit_env;
1592→    interp.match_env      = saved_match_env;
1593→    interp.eval_depth     = saved_eval_depth;
1594→    interp.flags          = saved_flags;
1595→    interp.jit_tco_expr   = saved_tco_expr;
1596→    interp.jit_tco_env    = saved_tco_env;
1597→    interp.tco_recycle_scope = saved_tco_recycle;
1598→    interp.reset_depth    = saved_reset_depth;
1599→    interp.handler_count  = saved_handler_count;
1600→    interp.current_scope  = saved_coro_scope;
1601→
1602→    // Propagate raise_pending from coro execution
1603→    if (coro_raise_pending) interp.flags.raise_pending = true;
1604→
1605→    // Stack overflow — coro hit guard page
1606→    if (coro.status == main::CoroStatus.CORO_DEAD) {
1607→        interp.handler_count = my_idx;
1608→        main::coro_destroy(coro, &interp.coro_pool);
1609→        return eval_error("stack overflow in handle body");
1610→    }
1611→
1612→    // Handle loop: process signals
1613→    Value* last_handler_v = null;
1614→    while (state.signaled) {
1615→        state.signaled = false;
1616→
1617→        // Pop handler for clause evaluation (clause may push its own)
1618→        interp.handler_count = my_idx;
1619→
1620→        // Find matching clause
1621→        EffectClause* clause = null;
1622→        for (usz j = 0; j < state.handler_copy.clause_count; j++) {
1623→            if ((uint)state.handler_copy.tags[j] == (uint)state.signal_tag) {
1624→                clause = &state.handler_copy.clauses[j];
1625→                break;
1626→            }
1627→        }
1628→
1629→        if (clause == null) {
1630→            // No matching clause — unhandled signal
1631→            main::coro_destroy(coro, &interp.coro_pool);
1632→            char[256] ubuf;
1633→            char[] utag = interp.symbols.get_name(state.signal_tag);
1634→            char[] uarg = interp.symbols.get_name(value_type_name(state.signal_arg, interp));
1635→            char[] umsg = io::bprintf(&ubuf, "unhandled effect '%s' with arg type %s", (ZString)utag, (ZString)uarg)!!;
1636→            return eval_error(umsg);
1637→        }
1638→
1639→        // Create continuation wrapping the suspended coro
1640→        Continuation* k = interp.alloc_lisp_continuation();
1641→        k.coro = coro;
1642→        k.is_fiber_based = true;
1643→        k.handle_state = &state;
1644→        Value* k_val = make_continuation(interp, k);
1645→
1646→        // Bind k and arg in clause environment
1647→        Env* clause_env = env.extend(interp, clause.k_name, k_val);
1648→        clause_env = clause_env.extend(interp, clause.arg_name, state.signal_arg);
1649→        // Also bind __k for resolve
1650→        clause_env = clause_env.extend(interp, interp.sym__k, k_val);
1651→
1652→        // Evaluate handler clause
1653→        last_handler_v = jit_eval(clause.handler_body, clause_env, interp);
1654→
1655→        // Check coro state after clause returns
1656→        if (coro.status == main::CoroStatus.CORO_COMPLETED) {
1657→            // resolve was called, body completed
1658→            Value* body_result = (Value*)coro.result;
1659→            main::coro_destroy(coro, &interp.coro_pool);
1660→            if (body_result != null && body_result.tag == ERROR) {
1661→                return eval_error(body_result.str_val.chars[:body_result.str_val.len]);
1662→            }
1663→            return eval_ok(body_result);
1664→        }
1665→
1666→        if (state.signaled) {
1667→            // Body hit another signal after being resumed — loop to dispatch
1668→            continue;
1669→        }
1670→
1671→        // Abort: clause didn't call resolve, coro is still suspended
1672→        main::coro_destroy(coro, &interp.coro_pool);
1673→        if (last_handler_v != null && last_handler_v.tag == ERROR) {
1674→            return eval_error(last_handler_v.str_val.chars[:last_handler_v.str_val.len]);
1675→        }
1676→        return eval_ok(last_handler_v);
1677→    }
1678→
1679→    // Normal completion (no signal)
1680→    interp.handler_count = my_idx;
1681→    Value* v = (Value*)coro.result;
1682→    main::coro_destroy(coro, &interp.coro_pool);
1683→
1684→    // Check for pending raise error
1685→    if (interp.flags.raise_pending) {
1686→        SymbolId raise_sym = interp.sym_raise;
1687→        for (usz ci = 0; ci < expr.handle.clause_count; ci++) {
1688→            if ((uint)expr.handle.clauses[ci].effect_tag == (uint)raise_sym) {
1689→                EffectClause* clause = &expr.handle.clauses[ci];
1690→                interp.flags.raise_pending = false;
1691→                Value* msg_val = make_string(interp, interp.raise_msg[:interp.raise_msg_len]);
1692→                Value* k_val = make_nil(interp);
1693→                Env* clause_env = env.extend(interp, clause.k_name, k_val);
1694→                clause_env = clause_env.extend(interp, clause.arg_name, msg_val);
1695→                Value* handler_v = jit_eval(clause.handler_body, clause_env, interp);
1696→                if (handler_v != null && handler_v.tag != ERROR) {
1697→                    return eval_ok(handler_v);
1698→                }
1699→                if (handler_v != null) {
1700→                    return eval_error(handler_v.str_val.chars[:handler_v.str_val.len]);
1701→                }
1702→                return eval_error("raise handler returned nil");
1703→            }
1704→        }
1705→    }
1706→
1707→    if (v != null && v.tag == ERROR) {
1708→        return eval_error(v.str_val.chars[:v.str_val.len]);
1709→    }
1710→    return eval_ok(v);
1711→}
