1055→fn void hashmap_set(HashMap* map, Value* key, Value* value, Interp* interp) {
1056→    // Grow at 70% load
1057→    if (map.count * 10 >= map.capacity * 7) {
1058→        hashmap_grow(map, interp);
1059→    }
1060→
1061→    // Promote key/value to root_scope — hashmap lives in root_scope,
1062→    // so its entries must survive child scope release
1063→    key = promote_to_root(key, interp);
1064→    value = promote_to_root(value, interp);
1065→
1066→    uint h = hash_value(key) & map.mask;
1067→    for (uint i = 0; i < map.capacity; i++) {
1068→        uint idx = (h + i) & map.mask;
1069→        HashEntry* entry = &map.entries[idx];
1070→        if (entry.key == null) {
1071→            entry.key = key;
1072→            entry.value = value;
1073→            map.count++;
1074→            return;
1075→        }
1076→        if (values_equal(entry.key, key)) {
1077→            entry.value = value;
1078→            return;
1079→        }
1080→    }
1081→}
