1083→fn bool hashmap_remove(HashMap* map, Value* key) {
1084→    uint h = hash_value(key) & map.mask;
1085→    for (uint i = 0; i < map.capacity; i++) {
1086→        uint idx = (h + i) & map.mask;
1087→        HashEntry* entry = &map.entries[idx];
1088→        if (entry.key == null) return false;
1089→        if (values_equal(entry.key, key)) {
1090→            // Backward shift delete
1091→            uint j = idx;
1092→            for (;;) {
1093→                uint next = (j + 1) & map.mask;
1094→                if (map.entries[next].key == null) break;
1095→                uint natural = hash_value(map.entries[next].key) & map.mask;
1096→                // Check if next entry would be displaced by removing j
1097→                // If natural position is between (j+1) and next, it's fine where it is
1098→                bool should_move;
1099→                if (j < next) {
1100→                    should_move = natural <= j || natural > next;
1101→                } else {
1102→                    should_move = natural <= j && natural > next;
1103→                }
1104→                if (!should_move) break;
1105→                map.entries[j] = map.entries[next];
1106→                j = next;
1107→            }
1108→            map.entries[j].key = null;
1109→            map.entries[j].value = null;
1110→            map.count--;
1111→            return true;
1112→        }
1113→    }
1114→    return false;
1115→}
