1133→fn Value* prim_dict(Value*[] args, Env* env, Interp* interp) {
1134→    if (args.len % 2 != 0) return raise_error(interp, "dict: expected even number of args");
1135→    uint cap = 16;
1136→    while (cap < (uint)args.len * 2) cap *= 2;
1137→    Value* v = make_hashmap(interp, cap);
1138→    for (usz i = 0; i < args.len; i += 2) {
1139→        hashmap_set(v.hashmap_val, args[i], args[i + 1], interp);
