2922→    // Yield values live in the fiber's call_scope (created by jit_eval_in_call_scope).
2923→    // When the fiber completes, that scope is released, invalidating all yield values.
2924→    // The caller may still hold pointers to previously yielded values, so we must
2925→    // copy each yield value into the caller's scope (current_scope, restored above).
2926→    if (interp.yield_value != null) {
2927→        return copy_to_parent(interp.yield_value, interp, interp.current_frame);
2928→    }
2929→    return make_nil(interp);
