2932→fn Value* prim_yield(Value*[] args, Env* env, Interp* interp) {
2933→    main::Coro* current = main::g_current_coro;
2934→    if (current == null) {
2935→        return raise_error(interp, "yield: not inside a fiber");
2936→    }
