2948→    usz         saved_reset_depth   = interp.reset_depth;
2949→    usz         saved_handler_count = interp.handler_count;
2950→    main::ScopeRegion* saved_coro_scope = interp.current_scope;
2951→
2952→    main::coro_suspend();
2953→
2954→    // Resumed — restore interp state
2955→    interp.jit_env        = saved_jit_env;
2956→    interp.match_env      = saved_match_env;
2957→    interp.eval_depth     = saved_eval_depth;
2958→    interp.flags          = saved_flags;
