2960→    interp.jit_tco_env    = saved_tco_env;
2961→    interp.reset_depth    = saved_reset_depth;
2962→    interp.handler_count  = saved_handler_count;
2963→    interp.current_scope  = saved_coro_scope;
2964→
2965→    return interp.resume_value != null ? interp.resume_value : make_nil(interp);
