1231→/** Sentinel value for empty slots in the destructor registry hash map. */
1232→const usz DESTRUCTOR_EMPTY_KEY = usz.max;
1233→
1234→/**
1235→ * DestructorRegistryEntry - A single entry in the hash map.
1236→ */
1237→struct DestructorRegistryEntry {
1238→    usz          key;   // typeid cast to usz, or DESTRUCTOR_EMPTY_KEY if empty
1239→    DestructorFn func;  // The destructor function
1240→}
1241→
1242→/**
1243→ * DestructorRegistry - O(1) hash map for type ID to destructor lookup.
1244→ *
1245→ * Uses open-addressing with linear probing. Automatically resizes when
1246→ * load factor exceeds 75%. Initial capacity is 16 slots.
1247→ */
1248→struct DestructorRegistry {
1249→    List{DestructorRegistryEntry} entries;
1250→    usz count;
1251→    usz capacity;
1252→}
1253→
1254→/**
1255→ * Hash function for typeid keys.
1256→ * Uses splitmix64-style mixing for good distribution.
1257→ */
1258→fn usz destructor_registry_hash(usz key) @inline {
1259→    ulong h = (ulong)key;
1260→    h ^= h >> 33;
1261→    h *= 0xff51afd7ed558ccd;
1262→    h ^= h >> 33;
1263→    h *= 0xc4ceb9fe1a85ec53;
1264→    h ^= h >> 33;
1265→    return (usz)h;
1266→}
1267→
1268→/**
1269→ * Initialize the destructor registry.
1270→ * Must be called before any register/find operations.
1271→ */
1272→fn void DestructorRegistry.init(DestructorRegistry* self) {
1273→    usz initial_capacity = 16;
1274→    self.capacity = initial_capacity;
1275→    self.count = 0;
1276→    self.entries = {};  // Ensure we start with an empty list
1277→    for (usz i = 0; i < initial_capacity; i++) {
1278→        DestructorRegistryEntry empty = { .key = DESTRUCTOR_EMPTY_KEY, .func = null };
1279→        self.entries.push(empty);
1280→    }
1281→}
1282→
1283→/**
1284→ * Release all resources held by the registry.
1285→ */
1286→fn void DestructorRegistry.release(DestructorRegistry* self) {
1287→    self.entries.free();
1288→    self.count = 0;
1289→    self.capacity = 0;
1290→}
1291→
1292→/**
1293→ * Resize the hash map when load factor is too high.
1294→ */
1295→fn void DestructorRegistry.resize(DestructorRegistry* self) {
1296→    usz new_capacity = self.capacity * 2;
1297→    List{DestructorRegistryEntry} old_entries = self.entries;
1298→    self.entries = {};
1299→    for (usz i = 0; i < new_capacity; i++) {
1300→        DestructorRegistryEntry empty = { .key = DESTRUCTOR_EMPTY_KEY, .func = null };
1301→        self.entries.push(empty);
1302→    }
1303→    self.capacity = new_capacity;
1304→    self.count = 0;
1305→    foreach (&entry : old_entries) {
1306→        if (entry.key != DESTRUCTOR_EMPTY_KEY) {
1307→            self.insert_entry(entry.key, entry.func);
1308→        }
1309→    }
1310→    old_entries.free();
1311→}
1312→
1313→/**
1314→ * Internal: Insert an entry by raw key.
1315→ */
1316→fn void DestructorRegistry.insert_entry(DestructorRegistry* self, usz key, DestructorFn func) {
1317→    if (self.count * 4 >= self.capacity * 3) {
1318→        self.resize();
1319→    }
1320→    usz mask = self.capacity - 1;
1321→    usz idx = destructor_registry_hash(key) & mask;
1322→    while (self.entries[idx].key != DESTRUCTOR_EMPTY_KEY) {
1323→        if (self.entries[idx].key == key) {
1324→            self.entries[idx].func = func;
1325→            return;
1326→        }
1327→        idx = (idx + 1) & mask;
1328→    }
1329→    self.entries[idx].key = key;
1330→    self.entries[idx].func = func;
1331→    self.count++;
1332→}
1333→
1334→/**
1335→ * Register a destructor for a type.
1336→ *
1337→ * @param tid  The runtime type ID
1338→ * @param func The destructor function to call
1339→ */
1340→fn void DestructorRegistry.register(DestructorRegistry* self, typeid tid, DestructorFn func) {
1341→    usz key = (usz)tid;
1342→    self.insert_entry(key, func);
1343→}
1344→
1345→/**
1346→ * Find the destructor for a type. O(1) average case.
1347→ *
1348→ * @param tid The runtime type ID to look up
1349→ * @return The destructor function, or null if none registered
1350→ */
1351→fn DestructorFn? DestructorRegistry.find(DestructorRegistry* self, typeid tid) {
1352→    if (self.capacity == 0) {
1353→        return DESTRUCTOR_NOT_FOUND~;
1354→    }
1355→    usz key = (usz)tid;
1356→    usz mask = self.capacity - 1;
1357→    usz idx = destructor_registry_hash(key) & mask;
1358→    usz start = idx;
1359→    do {
1360→        if (self.entries[idx].key == key) {
1361→            return self.entries[idx].func;
1362→        }
1363→        if (self.entries[idx].key == DESTRUCTOR_EMPTY_KEY) {
1364→            return DESTRUCTOR_NOT_FOUND~;
1365→        }
1366→        idx = (idx + 1) & mask;
1367→    } while (idx != start);
1368→    return DESTRUCTOR_NOT_FOUND~;
1369→}
