1491→ * The new region:
1492→ * - Gets a fresh or recycled RegionId
1493→ * - Has generation = previous generation + 1
1494→ * - Has refcount 2 (+1 creator, +1 parent)
1495→ * - Is registered as a child of the parent
1496→ */
1497→fn RegionHandle RegionRegistry.create_region(RegionRegistry* self, RegionHandle parent_handle) {
1498→    // --- Resolve parent (default to root if invalid handle) ---
1499→    RegionId parent_id;
1500→    if (self.is_valid_region(parent_handle)) {
1501→        parent_id = parent_handle.region_id;
1502→    } else {
1503→        parent_id = self.root_id;
1504→    }
1505→
1506→    // --- Get or recycle a RegionId ---
1507→    RegionId id;
1508→    if (self.recycled_region_ids.len() > 0) {
1509→        id = self.recycled_region_ids.pop()!!;
