1512→        self.next_region_id = (RegionId)((uint)self.next_region_id + 1);
1513→    }
1514→
1515→    // --- Grow storage arrays if needed ---
1516→    usz idx = (usz)(uint)id;
1517→    while (self.region_generations.len() <= idx) {
1518→        self.region_generations.push((Generation)0);
1519→        self.region_storage.push({});
1520→        self.region_alive_flags.push(false);
1521→        self.child_region_lists.push({});
1522→    }
1523→
1524→    // --- Bump generation to invalidate old handles ---
1525→    self.region_generations[idx] =
1526→        (Generation)((uint)self.region_generations[idx] + 1);
1527→    Generation gen = self.region_generations[idx];
1528→
1529→    // --- Create the region ---
1530→    Region region;
1531→    region.id = id;
1532→    region.generation = gen;
1533→    region.refcount = (RefCount)2;  // +1 creator, +1 parent
1534→    region.parent = parent_id;
1535→    region.live_object_count = 0;
1536→
1537→    self.region_storage[idx] = region;
1538→    self.region_alive_flags[idx] = true;
1539→    self.live_region_tracker.insert((uint)id);
