1553→// 9.4 Reference Counting
1554→// -----------------------------------------------------------------------------
1555→
1556→/**
1557→ * Increment a region's reference count.
1558→ *
1559→ * Call this when taking a new reference to a region (e.g., storing the handle).
1560→ *
1561→ * @param handle The region to retain
1562→ * @return The same handle (for chaining)
1563→ */
1564→fn RegionHandle RegionRegistry.retain_region(RegionRegistry* self, RegionHandle handle) {
1565→    assert(self.is_valid_region(handle));
1566→    usz idx = (usz)(uint)handle.region_id;
1567→    self.region_storage[idx].refcount =
1568→        (RefCount)((uint)self.region_storage[idx].refcount + 1);
1569→    return handle;
1570→}
