1572→/**
1573→ * Decrement a region's reference count.
1574→ *
1575→ * If refcount reaches 0, the region is destroyed:
1576→ * - Objects are promoted to parent
1577→ * - Children are reparented or destroyed
1578→ * - Ghost table is transferred to parent
1579→ *
1580→ * @param handle The region to release
1581→ */
1582→fn void RegionRegistry.release_region(RegionRegistry* self, RegionHandle handle) {
1583→    assert(self.is_valid_region(handle));
1584→    usz idx = (usz)(uint)handle.region_id;
1585→
1586→    // Guard against refcount underflow: if already 0, double-release is a bug
1587→    if ((uint)self.region_storage[idx].refcount == 0) {
1588→        return;
1589→    }
1590→
1591→    self.region_storage[idx].refcount =
1592→        (RefCount)((uint)self.region_storage[idx].refcount - 1);
1593→
1594→    if ((uint)self.region_storage[idx].refcount == 0) {
1595→        self.destroy_region(handle.region_id);
1596→    }
1597→}
