2857→    if (args.len < 1) return raise_error(interp, "resume: expected a fiber argument");
2858→    Value* fiber_val = args[0];
2859→    if (fiber_val == null || fiber_val.tag != FIBER) {
2860→        return raise_error(interp, "resume: argument must be a fiber");
2861→    }
2862→
2863→    main::Coro* coro = fiber_val.fiber_val;
2864→    if (coro == null) return raise_error(interp, "resume: null fiber");
2865→
2866→    if (coro.status == main::CoroStatus.CORO_COMPLETED || coro.status == main::CoroStatus.CORO_DEAD) {
2867→        return raise_error(interp, "resume: fiber already completed");
