144→/**
145→ * Create a new ScopeRegion, optionally as a child of `parent`.
146→ * If parent is non-null, it is retained (RC incremented).
147→ * Returns a scope with refcount=1 (the caller owns it).
148→ */
149→fn ScopeRegion* scope_create(ScopeRegion* parent = null) {
150→    ScopeRegion* scope;
151→
152→    // Try freelist first
153→    if (g_scope_freelist != null) {
154→        scope = g_scope_freelist;
155→        g_scope_freelist = scope.pool_next;
156→        g_scope_freelist_count--;
157→    } else {
158→        scope = (ScopeRegion*)mem::malloc(ScopeRegion.sizeof);
159→        scope.generation = 0;
160→    }
161→
162→    // Allocate initial chunk
163→    ScopeChunk* chunk = scope_chunk_alloc(SCOPE_CHUNK_INITIAL);
164→    chunk.next = null;
165→
166→    // Initialize scope
167→    scope.refcount = 1;
168→    scope.parent = parent;
169→    scope.chunks = chunk;
170→    scope.bump = scope_chunk_data(chunk);
171→    scope.limit = scope.bump + chunk.capacity;
172→    scope.dtors = null;
173→    scope.alloc_bytes = 0;
174→    scope.alloc_count = 0;
175→    scope.pool_next = null;
176→
177→    // Retain parent
178→    if (parent != null) {
179→        scope_retain(parent);
180→    }
181→
182→    return scope;
183→}
