185→/**
186→ * Increment the reference count of a scope.
187→ */
188→fn void scope_retain(ScopeRegion* scope) @inline {
189→    if (scope != null) scope.refcount++;
190→}
191→
192→/**
193→ * Decrement the reference count. Destroys the scope when RC hits 0.
194→ */
195→fn void scope_release(ScopeRegion* scope) @inline {
196→    if (scope == null) return;
197→    if (--scope.refcount == 0) {
198→        scope_destroy(scope);
199→    }
200→}
201→
202→/**
203→ * Run all registered destructors in reverse order (LIFO).
204→ * Does NOT free chunks or the scope itself — use for scope reuse.
205→ */
206→fn void scope_run_dtors(ScopeRegion* scope) {
207→    ScopeDtor* d = scope.dtors;
208→    while (d != null) {
209→        d.func(d.ptr);
210→        d = d.next;
211→    }
212→}
213→
214→/**
215→ * Destroy a scope: run destructors, release parent, free chunks, recycle struct.
216→ * Called when refcount reaches 0. MUST NOT be called directly — use scope_release.
217→ */
218→fn void scope_destroy(ScopeRegion* scope) {
219→    // 1. Run destructors (reverse order — LIFO)
220→    scope_run_dtors(scope);
221→
222→    // 2. Release parent scope (may cascade)
223→    if (scope.parent != null) {
224→        scope_release(scope.parent);
225→        scope.parent = null;
226→    }
227→
228→    // 3. Free all chunks
229→    ScopeChunk* c = scope.chunks;
230→    while (c != null) {
231→        ScopeChunk* next = c.next;
232→        mem::free(c);
233→        c = next;
234→    }
235→    scope.chunks = null;
236→    scope.bump = null;
237→    scope.limit = null;
238→    scope.dtors = null;
239→
240→    // 4. Recycle ScopeRegion struct (increment generation, add to freelist)
241→    scope.generation++;
242→    if (g_scope_freelist_count < SCOPE_FREELIST_MAX) {
243→        scope.pool_next = g_scope_freelist;
244→        g_scope_freelist = scope;
245→        g_scope_freelist_count++;
246→    } else {
247→        mem::free(scope);
248→    }
249→}
