255→/**
256→ * Slow path: allocate a new chunk when the current one is full.
257→ */
258→fn void* ScopeRegion.alloc_slow(ScopeRegion* self, usz aligned_size) {
259→    // Determine new chunk capacity: double the previous, or at least fit the request
260→    usz prev_cap = SCOPE_CHUNK_INITIAL;
261→    if (self.chunks != null) {
262→        prev_cap = self.chunks.capacity;
263→    }
264→    usz new_cap = prev_cap * 2;
265→    if (new_cap > SCOPE_CHUNK_MAX) new_cap = SCOPE_CHUNK_MAX;
266→    if (new_cap < aligned_size) new_cap = aligned_size;
267→
268→    ScopeChunk* chunk = scope_chunk_alloc(new_cap);
269→    chunk.next = self.chunks;
270→    self.chunks = chunk;
271→
272→    char* data = scope_chunk_data(chunk);
273→    self.bump = data + aligned_size;
274→    self.limit = data + chunk.capacity;
275→    self.alloc_bytes += aligned_size;
276→    self.alloc_count++;
277→    return (void*)data;
278→}
