280→/**
281→ * Bump-allocate `size` bytes from this scope. 8-byte aligned.
282→ * Fast path: ~3 instructions (load bump, add, compare).
283→ */
284→fn void* ScopeRegion.alloc(ScopeRegion* self, usz size) @inline {
285→    usz mask = 7;
286→    usz aligned = (size + mask) & ~mask;
287→    char* result = self.bump;
288→    char* new_bump = result + aligned;
289→    if (new_bump <= self.limit) {
290→        self.bump = new_bump;
291→        self.alloc_bytes += aligned;
292→        self.alloc_count++;
293→        return (void*)result;
294→    }
295→    return self.alloc_slow(aligned);
296→}
