314→// =============================================================================
315→// Scope reset (for loop reuse — Perceus reuse analysis)
316→// =============================================================================
317→
318→/**
319→ * Reset a scope for reuse: run destructors, reset bump pointer to start of first chunk.
320→ * Only safe when RC == 1 (no external references — nothing escaped).
321→ *
322→ * Frees overflow chunks (keeps only the first), resets bump to start.
323→ * O(1) amortized per loop iteration when no escapes occur.
324→ */
325→fn void scope_reset(ScopeRegion* scope) {
326→    // Run destructors first
327→    scope_run_dtors(scope);
328→
329→    // Free overflow chunks (keep only the oldest = last in linked list)
330→    ScopeChunk* keep = null;
331→    ScopeChunk* c = scope.chunks;
332→    while (c != null) {
333→        ScopeChunk* next = c.next;
334→        if (next == null) {
335→            // This is the oldest (first allocated) chunk — keep it
336→            keep = c;
337→        } else {
338→            mem::free(c);
339→        }
340→        c = next;
341→    }
342→
343→    // Reset to the kept chunk
344→    if (keep != null) {
345→        keep.next = null;
346→        scope.chunks = keep;
347→        scope.bump = scope_chunk_data(keep);
348→        scope.limit = scope.bump + keep.capacity;
349→    }
350→
351→    scope.dtors = null;
352→    scope.alloc_bytes = 0;
353→    scope.alloc_count = 0;
354→}
